    """
    Retorna informações sobre o módulo.
    """
    return {
        'name': 'html_preview',
        'display_name': 'HTML Preview',
        'description': 'Visualização de arquivos HTML',
        'supported_extensions': ['.html', '.htm'],
        'render_mode': 'iframe',
        'supports_edit': True,
        'webhook_payload_type': 'text'
    }
